//! Python parity harness for bot-math kernel modules.
//!
//! Loads `strategy/rust_fixtures/*.json` fixtures (generated by the
//! Python reference) and asserts byte-exact Rust output at the tolerance
//! stated in each fixture case.
//!
//! Each `parity_<module>` test iterates every case in the file and compares
//! Rust output to the Python `expected` within `tolerance`. Failures are
//! aggregated with per-case name/input/expected/actual/diff logging so a
//! single test invocation surfaces every mismatch.
//!
//! Env override: `DOL_MATH_PARITY_DIR` → absolute path to `rust_fixtures/`.

use serde::Deserialize;
use std::path::PathBuf;

use bot_math::{
    breakeven::{break_even_hold_at_mean, break_even_hold_fixed_point},
    cost::slippage,
    leverage::{bernstein_leverage_bound, critical_aum},
    ou::ou_time_averaged_spread,
    phi::{phi, phi_derivative},
    routing::{cap_routing, mandate_floor},
};
use bot_types::{AnnualizedRate, AumFraction, Dimensionless, HourlyRate, Hours, Mandate, Usd};

fn fixtures_dir() -> PathBuf {
    if let Ok(p) = std::env::var("DOL_MATH_PARITY_DIR") {
        return PathBuf::from(p);
    }
    // CARGO_MANIFEST_DIR → crates/bot-tests; ../ → crates; ../../ → bot-rs;
    // ../../../ → dol-public (monorepo root). Then strategy/rust_fixtures.
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .parent()
        .unwrap()
        .parent()
        .unwrap()
        .parent()
        .unwrap()
        .join("strategy")
        .join("rust_fixtures")
}

#[derive(Debug, Deserialize)]
struct Case<I, E> {
    name: String,
    input: I,
    expected: E,
    tolerance: f64,
    #[allow(dead_code)]
    #[serde(default)]
    notes: Option<String>,
}

fn load_cases<I, E>(filename: &str) -> Vec<Case<I, E>>
where
    I: for<'de> Deserialize<'de>,
    E: for<'de> Deserialize<'de>,
{
    let path = fixtures_dir().join(filename);
    let contents = std::fs::read_to_string(&path)
        .unwrap_or_else(|e| panic!("could not read fixture {}: {}", path.display(), e));
    serde_json::from_str(&contents)
        .unwrap_or_else(|e| panic!("could not parse fixture {}: {}", path.display(), e))
}

fn approx_eq(actual: f64, expected: f64, tol: f64) -> bool {
    if actual.is_nan() && expected.is_nan() {
        return true;
    }
    if !actual.is_finite() || !expected.is_finite() {
        return actual == expected;
    }
    (actual - expected).abs() <= tol.max(f64::EPSILON)
}

macro_rules! parity_scalar {
    ($test_name:ident, $file:expr, $input:ty, $call:expr) => {
        #[test]
        fn $test_name() {
            #[derive(Deserialize)]
            struct Expected {
                result: f64,
            }
            let cases: Vec<Case<$input, Expected>> = load_cases($file);
            assert!(!cases.is_empty(), "fixture {} has no cases", $file);
            let mut failures = Vec::new();
            for case in &cases {
                let actual = ($call)(&case.input);
                if !approx_eq(actual, case.expected.result, case.tolerance) {
                    failures.push(format!(
                        "[{}] actual={} expected={} tol={} diff={:.3e}",
                        case.name,
                        actual,
                        case.expected.result,
                        case.tolerance,
                        (actual - case.expected.result).abs()
                    ));
                }
            }
            assert!(
                failures.is_empty(),
                "{}/{} parity failures for {}:\n{}",
                failures.len(),
                cases.len(),
                $file,
                failures.join("\n")
            );
            println!("parity: {} OK ({} cases)", $file, cases.len());
        }
    };
}

// ── phi ──────────────────────────────────────────────────────────────────────
//
// phi.json mixes two case shapes: scalar `{input:{x:f64}, expected:{result:f64}}`
// and vector `{input:{xs:[f64]}, expected:{values:[f64]}}`. We test both.

#[test]
fn parity_phi() {
    let path = fixtures_dir().join("phi.json");
    let contents = std::fs::read_to_string(&path).expect("read phi.json");
    let cases: Vec<serde_json::Value> = serde_json::from_str(&contents).expect("parse phi.json");
    assert!(!cases.is_empty(), "no phi cases");
    let mut failures = Vec::new();
    let mut scalar_count = 0usize;
    let mut vector_count = 0usize;
    for case in &cases {
        let name = case["name"].as_str().unwrap_or("?").to_string();
        let tol = case["tolerance"].as_f64().unwrap_or(1e-12);
        let input = &case["input"];
        let expected = &case["expected"];
        // Dispatch phi(x) vs phi'(x) by case name prefix.
        let is_derivative = name.starts_with("phi_derivative_");
        if let Some(x) = input.get("x").and_then(|v| v.as_f64()) {
            scalar_count += 1;
            let got = if is_derivative {
                phi_derivative(x)
            } else {
                phi(x)
            };
            let exp = expected["result"].as_f64().unwrap_or(f64::NAN);
            if !approx_eq(got, exp, tol) {
                failures.push(format!(
                    "[{name}] ({}) x={x} got={got} exp={exp}",
                    if is_derivative { "φ'" } else { "φ" }
                ));
            }
        } else if let Some(xs_arr) = input.get("xs").and_then(|v| v.as_array()) {
            vector_count += 1;
            let xs: Vec<f64> = xs_arr.iter().filter_map(|v| v.as_f64()).collect();
            let empty_vec: Vec<serde_json::Value> = Vec::new();
            let expected_vals: Vec<f64> = expected["values"]
                .as_array()
                .unwrap_or(&empty_vec)
                .iter()
                .filter_map(|v| v.as_f64())
                .collect();
            if xs.len() != expected_vals.len() {
                failures.push(format!("[{name}] xs/values length mismatch"));
                continue;
            }
            for (x, exp) in xs.iter().zip(expected_vals.iter()) {
                let got = phi(*x);
                if !approx_eq(got, *exp, tol) {
                    failures.push(format!("[{name}] x={} got={} exp={}", x, got, exp));
                }
            }
        }
    }
    assert!(
        failures.is_empty(),
        "{} phi failures ({} scalar, {} vector cases):\n{}",
        failures.len(),
        scalar_count,
        vector_count,
        failures.join("\n")
    );
    println!(
        "parity: phi.json OK ({} scalar + {} vector cases)",
        scalar_count, vector_count
    );
}

