// ── break_even_hold (mixed at-mean + fixed-point cases) ─────────────────────
//
// Cases named `be_at_mean_*` use `break_even_hold_at_mean` (closed form).
// Cases named `be_fixed_point_*` require the fixed-point iteration because
// they supply `d0` and `theta_ou`.

#[test]
fn parity_break_even_hold() {
    let path = fixtures_dir().join("break_even_hold.json");
    let contents = std::fs::read_to_string(&path).expect("read break_even_hold.json");
    let cases: Vec<serde_json::Value> =
        serde_json::from_str(&contents).expect("parse break_even_hold.json");
    assert!(!cases.is_empty(), "no cases");
    let mut failures = Vec::new();
    for case in &cases {
        let name = case["name"].as_str().unwrap_or("?").to_string();
        let tol = case["tolerance"].as_f64().unwrap_or(1e-9);
        let input = &case["input"];
        let exp = case["expected"]["result"].as_f64().unwrap_or(f64::NAN);
        let mu = input["mu"].as_f64().expect("mu");
        let c = input["c_round_trip"].as_f64().expect("c_round_trip");
        let rho = input["rho_comp"].as_f64().unwrap_or(0.0);
        let got = if name.starts_with("be_fixed_point_") {
            let d0 = input["d0"].as_f64().expect("d0");
            let theta = input["theta_ou"].as_f64().expect("theta_ou");
            let initial =
                break_even_hold_at_mean(AnnualizedRate(mu), Dimensionless(c), Dimensionless(rho))
                    .map(|h| h.0)
                    .unwrap_or(100.0);
            break_even_hold_fixed_point(
                AnnualizedRate(d0),
                AnnualizedRate(mu),
                HourlyRate(theta),
                Dimensionless(c),
                Dimensionless(rho),
                Hours(initial),
                500,
                1e-9,
            )
            .map(|h| h.0)
            .unwrap_or(f64::NAN)
        } else {
            break_even_hold_at_mean(AnnualizedRate(mu), Dimensionless(c), Dimensionless(rho))
                .map(|h| h.0)
                .unwrap_or(f64::NAN)
        };
        if !approx_eq(got, exp, tol) {
            failures.push(format!(
                "[{name}] got={got} exp={exp} tol={tol} diff={:.3e}",
                (got - exp).abs()
            ));
        }
    }
    assert!(
        failures.is_empty(),
        "{}/{} break_even failures:\n{}",
        failures.len(),
        cases.len(),
        failures.join("\n")
    );
    println!("parity: break_even_hold.json OK ({} cases)", cases.len());
}

