// ── critical_aum ─────────────────────────────────────────────────────────────

// critical_aum fixture uses JSON "inf" strings for infinite results.
// We use a raw serde_json pass to handle both numeric and "inf" expected values.
#[test]
fn parity_critical_aum() {
    let path = fixtures_dir().join("critical_aum.json");
    let contents = std::fs::read_to_string(&path).expect("read critical_aum.json");
    let cases: Vec<serde_json::Value> =
        serde_json::from_str(&contents).expect("parse critical_aum.json");
    assert!(!cases.is_empty());
    let mut failures = Vec::new();
    for case in &cases {
        let name = case["name"].as_str().unwrap_or("?").to_string();
        let tol = case["tolerance"].as_f64().unwrap_or(1e-6);
        let input = &case["input"];
        let pi_pac = input["pi_pac"].as_f64().expect("pi_pac");
        let tau_be = input["tau_be_h"].as_f64().expect("tau_be_h");
        let tau = input["tau_h"].as_f64().expect("tau_h");
        let theta = input["theta_impact"].as_f64().expect("theta_impact");
        let lev = input["leverage"].as_u64().expect("leverage") as u32;
        let m_pos = input["m_pos"].as_f64().expect("m_pos");
        let got = critical_aum(
            Usd(pi_pac),
            Hours(tau_be),
            Hours(tau),
            Dimensionless(theta),
            lev,
            AumFraction(m_pos),
        )
        .0;
        // Expected may be a number or the string "inf"/"Infinity".
        let exp_v = &case["expected"]["result"];
        let exp = if let Some(x) = exp_v.as_f64() {
            x
        } else if let Some(s) = exp_v.as_str() {
            match s.to_ascii_lowercase().as_str() {
                "inf" | "+inf" | "infinity" => f64::INFINITY,
                "-inf" | "-infinity" => f64::NEG_INFINITY,
                "nan" => f64::NAN,
                other => {
                    failures.push(format!("[{name}] unknown expected string: {other}"));
                    continue;
                }
            }
        } else {
            failures.push(format!("[{name}] expected is neither number nor string"));
            continue;
        };
        if !approx_eq(got, exp, tol) {
            failures.push(format!(
                "[{name}] got={got} exp={exp} tol={tol} diff={:.3e}",
                (got - exp).abs()
            ));
        }
    }
    assert!(
        failures.is_empty(),
        "{}/{} critical_aum failures:\n{}",
        failures.len(),
        cases.len(),
        failures.join("\n")
    );
    println!("parity: critical_aum.json OK ({} cases)", cases.len());
}

// ── mandate_floor ────────────────────────────────────────────────────────────

#[derive(Deserialize)]
struct MandateFloorInput {
    cust_min: f64,
    buf_min: f64,
    cut_customer: f64,
    cut_buffer: f64,
}

parity_scalar!(
    parity_mandate_floor,
    "mandate_floor.json",
    MandateFloorInput,
    |i: &MandateFloorInput| {
        let m = Mandate {
            customer_apy_min: AnnualizedRate(i.cust_min),
            buffer_apy_min: AnnualizedRate(i.buf_min),
            cut_customer: Dimensionless(i.cut_customer),
            cut_buffer: Dimensionless(i.cut_buffer),
            ..Mandate::default()
        };
        mandate_floor(&m).0
    }
);

// ── cap_routing ──────────────────────────────────────────────────────────────

#[derive(Deserialize)]
struct CapRoutingInput {
    vault_gross: f64,
    #[serde(default, rename = "cust_max")]
    customer_apy_max: Option<f64>,
    #[serde(default, rename = "buf_max")]
    buffer_apy_max: Option<f64>,
    #[serde(default)]
    cut_customer: Option<f64>,
    #[serde(default)]
    cut_buffer: Option<f64>,
    #[serde(default)]
    cut_reserve: Option<f64>,
}

#[derive(Deserialize)]
struct CapRoutingExpected {
    customer: f64,
    buffer: f64,
    reserve: f64,
}

#[test]
fn parity_cap_routing() {
    let cases: Vec<Case<CapRoutingInput, CapRoutingExpected>> = load_cases("cap_routing.json");
    assert!(!cases.is_empty(), "no cap_routing cases");
    let mut failures = Vec::new();
    for case in &cases {
        let base = Mandate::default();
        let m = Mandate {
            customer_apy_max: AnnualizedRate(
                case.input
                    .customer_apy_max
                    .unwrap_or(base.customer_apy_max.0),
            ),
            buffer_apy_max: AnnualizedRate(
                case.input.buffer_apy_max.unwrap_or(base.buffer_apy_max.0),
            ),
            cut_customer: Dimensionless(case.input.cut_customer.unwrap_or(base.cut_customer.0)),
            cut_buffer: Dimensionless(case.input.cut_buffer.unwrap_or(base.cut_buffer.0)),
            cut_reserve: Dimensionless(case.input.cut_reserve.unwrap_or(base.cut_reserve.0)),
            ..base
        };
        let alloc = cap_routing(AnnualizedRate(case.input.vault_gross), &m);
        let tol = case.tolerance;
        if !approx_eq(alloc.customer.0, case.expected.customer, tol)
            || !approx_eq(alloc.buffer.0, case.expected.buffer, tol)
            || !approx_eq(alloc.reserve.0, case.expected.reserve, tol)
        {
            failures.push(format!(
                "[{}] actual=({}, {}, {}) expected=({}, {}, {})",
                case.name,
                alloc.customer.0,
                alloc.buffer.0,
                alloc.reserve.0,
                case.expected.customer,
                case.expected.buffer,
                case.expected.reserve,
            ));
        }
    }
    assert!(
        failures.is_empty(),
        "{}/{} cap_routing failures:\n{}",
        failures.len(),
        cases.len(),
        failures.join("\n")
    );
    println!("parity: cap_routing.json OK ({} cases)", cases.len());
}
